    long long validSubstringCount(string word1, string word2) {
        long long count = 0;
        int word2Len = word2.length();
        unordered_map<char, int> word2Count;
        for (char c : word2) {
            word2Count[c]++;
        }
        int word1Len = word1.length();
        for (int i = 0; i <= word1Len - word2Len; i++) {
            unordered_map<char, int> currCount;
            for (int j = i; j < i + word2Len; j++) {
                currCount[word1[j]]++;
            }
            bool isValid = true;
            for (auto p : word2Count) {
                if (currCount[p.first] < p.second) {
                    isValid = false;
                    break;
                }
            }
            if (isValid) {
                count++;
            }
        }
        return count;
    }
};```
